28→export function createWall(start, end, thickness = WALL_THICKNESS) {
29→  return {
30→    id: generateId('wall'),
31→    start: { x: start.x, y: start.y },
32→    end: { x: end.x, y: end.y },
33→    thickness,
34→  };
