47→export function createWindow(wallId, offset, width = WINDOW_WIDTH) {
48→  return {
49→    id: generateId('win'),
50→    wallId,
51→    offset,
52→    width,
53→  };
54→}
55→
56→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
57→  const area = polygonArea(points);
58→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
59→  return {
60→    id: generateId('room'),
61→    name,
62→    points: points.map(p => ({ x: p.x, y: p.y })),
63→    labelPosition: { ...centroid },
64→    color,
65→    area,
66→  };
67→}
