155→export default function PropertiesPanel() {
156→  const { project, dispatch } = useProject();
157→  const { selectedId, selectedType, activeFloorId, dispatch: editorDispatch } = useEditor();
158→  const floor = project.floors.find(f => f.id === activeFloorId);
159→
160→  const handleDelete = () => {
161→    if (!selectedId) return;
162→    if (selectedType === 'wall') {
163→      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
164→    } else if (selectedType === 'door') {
165→      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
166→    } else if (selectedType === 'window') {
167→      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
168→    } else if (selectedType === 'room') {
169→      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
170→    }
171→    editorDispatch({ type: 'DESELECT' });
172→  };
173→
174→  let content = <ProjectSummary project={project} floor={floor} />;
175→
176→  if (selectedId && floor) {
177→    if (selectedType === 'wall') {
178→      const wall = floor.walls.find(w => w.id === selectedId);
179→      if (wall) {
180→        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} />;
181→      }
182→    } else if (selectedType === 'door') {
183→      const door = floor.doors.find(d => d.id === selectedId);
184→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
185→      if (door) {
186→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} />;
187→      }
188→    } else if (selectedType === 'window') {
189→      const win = floor.windows.find(w => w.id === selectedId);
190→      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
191→      if (win) {
192→        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} />;
193→      }
194→    } else if (selectedType === 'room') {
195→      const room = floor.rooms.find(r => r.id === selectedId);
196→      if (room) {
197→        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
198→      }
199→    }
200→  }
201→
202→  return (
203→    <div className={styles.panel}>
204→      {content}
205→      {selectedId && (
206→        <button className={styles.deleteBtn} onClick={handleDelete}>
207→          Delete {selectedType}
208→        </button>
209→      )}
210→    </div>
211→  );
212→}
