129→        ...f,
130→        rooms: action.rooms,
131→      }));
132→
133→    case 'MARK_SAVED':
134→      return {
135→        ...state,
136→        isDirty: false,
137→        lastSavedAt: new Date().toISOString(),
138→      };
139→
140→    default:
141→      return state;
142→  }
143→}
