  1→import { wallOutline } from '@/geometry/wallGeometry';
  2→
  3→const HANDLE_SIZE = 8; // px, will use vectorEffect
  4→
  5→function WallSelection({ wall, zoom }) {
  6→  const outline = wallOutline(wall);
  7→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
  8→  const handleR = HANDLE_SIZE / zoom;
  9→
 10→  return (
 11→    <g>
 12→      <polygon
 13→        points={points}
 14→        fill="var(--color-selection-fill)"
 15→        stroke="var(--color-selection)"
 16→        strokeWidth={2}
 17→        strokeDasharray="6 3"
 18→        vectorEffect="non-scaling-stroke"
 19→      />
 20→      {/* Endpoint handles */}
 21→      <rect
 22→        data-handle="start"
 23→        x={wall.start.x - handleR / 2}
 24→        y={wall.start.y - handleR / 2}
 25→        width={handleR}
 26→        height={handleR}
 27→        fill="white"
 28→        stroke="var(--color-selection)"
 29→        strokeWidth={2}
 30→        vectorEffect="non-scaling-stroke"
 31→        style={{ cursor: 'move' }}
 32→      />
 33→      <rect
 34→        data-handle="end"
 35→        x={wall.end.x - handleR / 2}
 36→        y={wall.end.y - handleR / 2}
 37→        width={handleR}
 38→        height={handleR}
 39→        fill="white"
 40→        stroke="var(--color-selection)"
 41→        strokeWidth={2}
 42→        vectorEffect="non-scaling-stroke"
 43→        style={{ cursor: 'move' }}
 44→      />
 45→    </g>
 46→  );
 47→}
